import (
	"context"
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
)
func (a *adapter) SetFoo(ctx context.Context, input subscriptionsync.SetFooInput) error {
	return entutils.TransactingRepoWithNoValue(ctx, a, func(ctx context.Context, tx *adapter) error {
		return tx.db.SubscriptionBillingSyncState.Update().SetFoo(input.Foo).Where(subscriptionbillingsyncstate.SubscriptionID(input.ID)).Exec(ctx)
	})
}

import (
	"errors"; "fmt"
	"github.com/openmeterio/openmeter/pkg/clock"
	"github.com/openmeterio/openmeter/pkg/pagination"
)
func (r *Reconciler) ProcessBatch(ctx context.Context, in ProcessBatchInput) error {
	pageIndex := 1
	var outErr error
	for {
		subs, err := r.subscriptionService.List(ctx, subscription.ListSubscriptionsInput{Page: pagination.Page{PageNumber: pageIndex, PageSize: defaultWindowSize}})
		if err != nil { return err }
		if len(subs.Items) == 0 { break }
		pageIndex++
	}
	return outErr
}
